const wb = $('Webhook_Multipart').first();
const body = wb.json.body || wb.json;
const full = $('Set_Config_Provisorio').first().json || {};
const skip = new Set(['headers', 'params', 'query', 'body', 'webhookUrl', 'executionMode']);
const cfg = {};
for (const [k, v] of Object.entries(full)) {
  if (!skip.has(k)) cfg[k] = v;
}
const b = wb.binary || {};
const keys = Object.keys(b);
if (!keys.length) {
  throw new Error('No hay archivos binarios. El nodo Set no reenvía binario: se lee de Webhook_Multipart. Enviá multipart con el campo "images" (uno o más) o ejecutá desde el webhook con archivo.');
}
const user_notes = body.user_notes || body.notes || '';
const batch_id = body.batch_id || $execution.id;
return keys.map((key, index) => ({
  json: {
    ...cfg,
    batch_id,
    user_notes: String(user_notes),
    filename: b[key].fileName || `ticket_${index}.jpg`,
    binaryKey: key,
  },
  binary: { image: b[key] },
}));

const orig = $input.all();
if (!orig.length) throw new Error('Sin archivos: el nodo anterior debe enviar los ítems (p. ej. SplitOut con binario por ticket).');

function mpField(boundary, name, value) {
  const head = Buffer.from(
    `--${boundary}\r\nContent-Disposition: form-data; name="${name}"\r\n\r\n`,
    'utf-8',
  );
  return Buffer.concat([head, Buffer.from(String(value), 'utf-8'), Buffer.from('\r\n', 'utf-8')]);
}

function mpFilePart(boundary, fieldName, filename, buf, mimeType) {
  const safeName = (String(filename || 'file').replace(/"/g, '_').replace(/[^a-zA-Z0-9._-]/g, '_').replace(/_+/g, '_').slice(0, 200) || 'upload');
  const mime = mimeType || 'application/octet-stream';
  const header = Buffer.from(
    `--${boundary}\r\nContent-Disposition: form-data; name="${fieldName}"; filename="${safeName}"\r\nContent-Type: ${mime}\r\n\r\n`,
    'utf-8',
  );
  return Buffer.concat([header, buf, Buffer.from('\r\n', 'utf-8')]);
}

const batch_id = String(orig[0].json.batch_id || $execution.id);
const un = String(orig[0].json.user_notes || '');
const boundary = 'n8n_' + Math.random().toString(36).slice(2) + '_' + Date.now();

const parts = [];
parts.push(mpField(boundary, 'batch_id', batch_id));
if (un) parts.push(mpField(boundary, 'user_notes', un));
parts.push(mpField(boundary, 'drive_links_json', '[]'));

for (let i = 0; i < orig.length; i++) {
  const it = orig[i];
  const bin = it.binary?.image;
  let buf;
  if (bin && bin.data) {
    buf = Buffer.from(bin.data, 'base64');
  } else if (this.helpers.getBinaryDataBuffer) {
    buf = await this.helpers.getBinaryDataBuffer(i, 'image');
  } else {
    throw new Error('No se pudo leer el binario del ítem ' + i);
  }
  const fn = it.json.filename || `ticket_${i}.bin`;
  const mime = bin?.mimeType || bin?.fileType || 'application/octet-stream';
  parts.push(mpFilePart(boundary, 'images', fn, buf, mime));
}

parts.push(Buffer.from(`--${boundary}--\r\n`, 'utf-8'));
const body = Buffer.concat(parts);

let base = String(orig[0].json.cloud_run_base || '').trim();
while (base.endsWith('/')) base = base.slice(0, -1);
if (!base) throw new Error('Falta cloud_run_base (Set_Config_Provisorio)');
const url = `${base}/process-batch`;
const secret = String(orig[0].json.x_autodoc_secret || '');
if (!secret) throw new Error('Falta x_autodoc_secret (Set_Config_Provisorio)');

let lastErr;
let parsed;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: {
        'Content-Type': `multipart/form-data; boundary=${boundary}`,
        'X-Autodoc-Secret': secret,
      },
      body,
      timeout: 180000,
    });
    parsed = typeof res === 'string' ? JSON.parse(res) : res;
    lastErr = null;
    break;
  } catch (e) {
    lastErr = e;
    if (attempt < 3) await new Promise((r) => setTimeout(r, 2000 * attempt));
  }
}
function formatProcessBatchErr(e) {
  const msg = e.message || String(e);
  const st = e.statusCode || e.status || e.response?.status || e.response?.statusCode || '';
  let raw = e.response?.body ?? e.response?.data ?? e.body ?? e.cause?.response?.body;
  if (typeof raw === 'string') {
    try { raw = JSON.parse(raw); } catch (_) {}
  }
  let tail = '';
  if (raw && typeof raw === 'object') {
    const d = raw.detail || raw.error || '';
    const bid = raw.batch_id || '';
    let rsum = '';
    const results = raw.results;
    if (Array.isArray(results) && results.length) {
      const x = results[0];
      rsum = (x.filename || '') + ': ' + (x.detail || x.error || '');
    }
    tail = ' | ' + JSON.stringify({ detail: d, batch_id: bid, primer_archivo: rsum }).slice(0, 2000);
  } else if (raw) {
    tail = ' | ' + String(raw).slice(0, 1500);
  }
  return 'Cloud Run /process-batch: ' + (st ? st + ' ' : '') + msg + tail;
}
if (lastErr) {
  throw new Error(formatProcessBatchErr(lastErr));
}

const curation_url = parsed.curation_url || parsed.curationUrl;
const task_id = parsed.task_id || parsed.taskId;
const out_batch_id = parsed.batch_id || batch_id;
if (!curation_url) {
  const d = parsed.detail || parsed.error || '';
  throw new Error(
    'Cloud Run no devolvió curation_url' +
      (d ? ': ' + d : '') +
      '. Respuesta: ' +
      JSON.stringify(parsed).slice(0, 1200)
  );
}

return [{ json: { curation_url, task_id, batch_id: out_batch_id } }];
